+type AgentRunResult = {
+  content: string;
+  isError: boolean;
+};
+
+const EMPTY_DELEGATION_RESULT = "The delegated agent completed without producing text.";
+
+function toolUseStreamResponse(toolUseId: string, input: unknown): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "assistant",
+      message: {
+        content: [{
+          type: "tool_use",
+          id: toolUseId,
+          name: "delegate_task",
+          input,
+        }],
+      },
+    },
+  };
+}
+
+function toolResultStreamResponse(toolUseId: string, result: AgentRunResult): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "user",
+      message: {
+        content: [{
+          type: "tool_result",
+          tool_use_id: toolUseId,
+          is_error: result.isError,
+          content: result.content,
+        }],
+      },
+    },
+  };
+}
+
+function getDelegationInput(input: unknown): { agentId: string; instructions: string } | undefined {
+  if (!input || typeof input !== "object") return undefined;
+  const { agent_id, instructions } = input as Record<string, unknown>;
+  if (typeof agent_id !== "string" || typeof instructions !== "string") return undefined;
+  return { agentId: agent_id, instructions };
+}
+
+async function drainAgentRun(
+  run: AsyncGenerator<StreamResponse, AgentRunResult>
+): Promise<{ events: StreamResponse[]; result: AgentRunResult }> {
+  const events: StreamResponse[] = [];
+  while (true) {
+    const next = await run.next();
+    if (next.done) return { events, result: next.value };
+    events.push(next.value);
+  }
+}
+
+/**
+ * Run an agent until it completes.  delegate_task calls are resolved recursively
+ * and their results are supplied as user context when the calling agent resumes.
+ */
+async function* runAgentConversation(
+  agentId: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  ancestry: string[],
+  streamText: boolean,
+  streamProviderErrors: boolean
+): AsyncGenerator<StreamResponse, AgentRunResult> {
+  if (ancestry.includes(agentId)) {
+    const error = `Circular agent delegation detected: ${[...ancestry, agentId].join(" -> ")}`;
+    yield { type: "error", error };
+    return { content: error, isError: true };
+  }
+
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+  if (!provider || !agentConfig) {
+    const error = `Agent '${agentId}' not found or provider not available`;
+    // Missing agents are actionable protocol errors even when they occur below a delegate.
+    yield { type: "error", error };
+    return { content: error, isError: true };
+  }
+
+  const output: string[] = [];
+  const context: ProviderChatRequest["context"] = [];
+  let generatedToolUseId = 0;
+
+  try {
+    while (true) {
+      let delegated = false;
+      const providerRequest: ProviderChatRequest = {
+        message: request.message,
+        sessionId: request.sessionId,
+        requestId: request.requestId,
+        workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+        context,
+      };
+
+      for await (const response of provider.executeChat(providerRequest, {
+        debugMode,
+        abortController,
+        temperature: agentConfig.config?.temperature,
+        maxTokens: agentConfig.config?.maxTokens,
+      })) {
+        if (response.type === "text") {
+          const content = response.content || "";
+          output.push(content);
+          if (streamText) {
+            yield {
+              type: "claude_json",
+              data: { type: "assistant", content, model: response.metadata?.model },
+            };
+          }
+          continue;
+        }
+
+        if (response.type === "tool_use" && response.toolName === "delegate_task") {
+          const toolUseId = response.toolUseId || `delegate_task_${++generatedToolUseId}`;
+          yield toolUseStreamResponse(toolUseId, response.toolInput || {});
+
+          const delegation = getDelegationInput(response.toolInput);
+          let result: AgentRunResult;
+          if (!delegation) {
+            result = { content: "delegate_task requires string agent_id and instructions.", isError: true };
+          } else {
+            const child = await drainAgentRun(runAgentConversation(
+              delegation.agentId,
+              { ...request, message: delegation.instructions },
+              abortController,
+              debugMode,
+              [...ancestry, agentId],
+              false,
+              false
+            ));
+            for (const event of child.events) yield event;
+            result = child.result;
+          }
+
+          if (!result.content) result.content = EMPTY_DELEGATION_RESULT;
+          yield toolResultStreamResponse(toolUseId, result);
+          context.push({
+            role: "user",
+            content: JSON.stringify({
+              type: "tool_result",
+              is_error: result.isError,
+              content: result.content,
+              tool_use_id: toolUseId,
+            }),
+          });
+          delegated = true;
+          break;
+        }
+
+        if (response.type === "error") {
+          const error = response.error || "Agent run failed";
+          if (streamProviderErrors) yield { type: "error", error };
+          return { content: error, isError: true };
+        }
+
+        if (response.type === "done") break;
+      }
+
+      if (!delegated) return { content: output.join(""), isError: false };
+    }
+  } catch (error) {
+    const message = error instanceof Error ? error.message : String(error);
+    if (streamProviderErrors) yield { type: "error", error: message };
+    return { content: message, isError: true };
+  }
+}
